#!/bin/bash
# Uninstall script for Linear
# Generated by IntuneBrew

# Exit on error
set -e

echo "Uninstalling Linear..."

# Check if running as root
if [ "$EUID" -ne 0 ]; then
  echo "Please run as root"
  exit 1
fi

# Kill application process if running
echo "Stopping Linear if running..."
pkill -f "Linear" 2>/dev/null || true

# Remove /Applications/Linear.app
echo "Removing /Applications/Linear.app..."
if [ -d "/Applications/Linear.app" ]; then
    rm -rf "/Applications/Linear.app" 2>/dev/null || true
elif [ -f "/Applications/Linear.app" ]; then
    rm -f "/Applications/Linear.app" 2>/dev/null || true
fi

